package main

import (
	"fmt"
	"reflect"

	"github.com/pocketbase/pocketbase/core"
)

func main() {
	c := core.NewBaseCollection("test")
	val := reflect.ValueOf(c).Elem()
	typ := val.Type()
	for i := 0; i < typ.NumField(); i++ {
		field := typ.Field(i)
		fmt.Printf("Field: %s, Type: %s, Anonymous: %t\n", field.Name, field.Type, field.Anonymous)
		if field.Anonymous {
			subTyp := field.Type
			if subTyp.Kind() == reflect.Pointer {
				subTyp = subTyp.Elem()
			}
			if subTyp.Kind() == reflect.Struct {
				for j := 0; j < subTyp.NumField(); j++ {
					subField := subTyp.Field(j)
					fmt.Printf("  SubField: %s, Type: %s\n", subField.Name, subField.Type)
				}
			}
		}
	}
}

